import{_ as t}from"./chunks/homepage.DZZjIHGg.js";import{_ as o,a as r}from"./chunks/deletecard.JRCLAEit.js";import{_ as a,o as i,c as n,ae as s}from"./chunks/framework.C00B0EYs.js";const b=JSON.parse('{"title":"Home and Projects","description":"Use the home screen to create, open, import, search, and manage projects.","frontmatter":{"title":"Home and Projects","description":"Use the home screen to create, open, import, search, and manage projects."},"headers":[],"relativePath":"docs/guide/home.md","filePath":"docs/guide/home.md"}'),c={name:"docs/guide/home.md"};function l(p,e,h,d,m,u){return i(),n("div",null,[...e[0]||(e[0]=[s('<h1 id="home-and-projects" tabindex="-1">Home and Projects <a class="header-anchor" href="#home-and-projects" aria-label="Permalink to &quot;Home and Projects&quot;">​</a></h1><p>The Home screen is your project hub. It is where you create new work, reopen existing files, import external <code>.msep</code> files, and browse recent projects.</p><p><img src="'+t+'" alt="Motor Sound Editor home gallery"></p><h2 id="sidebar-actions" tabindex="-1">Sidebar actions <a class="header-anchor" href="#sidebar-actions" aria-label="Permalink to &quot;Sidebar actions&quot;">​</a></h2><p>The left sidebar is the main action area for starting or resuming work:</p><ul><li><strong>New Project</strong> opens the new-project dialog and creates a fresh working document.</li><li><strong>Open File</strong> opens an existing <code>.msep</code> file from disk.</li><li><strong>Import File</strong> brings an existing <code>.msep</code> file into the app&#39;s recent-project flow. You can also drag an <code>.msep</code> file onto the Home screen to import it.</li><li><strong>Settings</strong> is present in the layout, but there is no finished settings screen in the current user-facing build.</li></ul><h2 id="recent-projects" tabindex="-1">Recent projects <a class="header-anchor" href="#recent-projects" aria-label="Permalink to &quot;Recent projects&quot;">​</a></h2><p><img src="'+o+'" alt="Project card"></p><p>The main area shows recent projects as cards. Each card can include:</p><ul><li>the project name</li><li>the last modified timestamp</li><li>a compact track preview graphic</li></ul><p>This area is meant to reduce context switching. You can identify and reopen a project visually instead of relying only on file names.</p><h2 id="search" tabindex="-1">Search <a class="header-anchor" href="#search" aria-label="Permalink to &quot;Search&quot;">​</a></h2><p>The search field filters the recent-project list by text.</p><p>If your naming scheme is consistent, for example by train class, operator, or project stage, search becomes especially effective.</p><h2 id="sorting" tabindex="-1">Sorting <a class="header-anchor" href="#sorting" aria-label="Permalink to &quot;Sorting&quot;">​</a></h2><p>The Home screen supports two common sort modes:</p><ul><li><strong>Date</strong>: best when you want to return to the project you edited most recently.</li><li><strong>Name</strong>: best when you manage multiple projects in parallel and rely on naming conventions.</li></ul><p>Date sorting is usually better during active production, while name sorting is more useful for library-style browsing.</p><h2 id="opening-a-project" tabindex="-1">Opening a project <a class="header-anchor" href="#opening-a-project" aria-label="Permalink to &quot;Opening a project&quot;">​</a></h2><p>You can open a project from these entry points:</p><ul><li><strong>Open File</strong>: choose an <code>.msep</code> file and open it directly.</li><li><strong>Project Card</strong>: click a project card in the recent-project area.</li></ul><p>If the file is valid, the app loads the project metadata, tracks, curves, and packaged audio into the editor.</p><h2 id="removing-a-project-from-the-recent-list" tabindex="-1">Removing a project from the recent list <a class="header-anchor" href="#removing-a-project-from-the-recent-list" aria-label="Permalink to &quot;Removing a project from the recent list&quot;">​</a></h2><p><img src="'+r+'" alt="Delete card"></p><p>The recent-project view can remove an entry from the recent list. Right click a card to open the menu, then choose <strong>Delete</strong>.</p><p>This only affects the recent list. It does not delete the actual project file from disk. Common reasons include:</p><ul><li>the file path has changed</li><li>the entry is no longer useful</li><li>you want a cleaner recent-project panel</li></ul><h2 id="new-project-fields" tabindex="-1">New project fields <a class="header-anchor" href="#new-project-fields" aria-label="Permalink to &quot;New project fields&quot;">​</a></h2><p>When you create a new project, the app asks for core metadata and simulator defaults. In practice this includes:</p><ul><li>project name</li><li>maximum speed</li><li>acceleration</li></ul><p>These values do more than label the file. They also affect curve speed-range limits and how the preview system interprets the project.</p>',31)])])}const y=a(c,[["render",l]]);export{b as __pageData,y as default};
